import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const readBatch = await callMcpSkillsParallel({
    label: "politics-event-discovery",
    calls: [
      {
        key: "top-markets",
        toolId,
        toolName: "get_top_markets",
        args: {
          category: "politics",
          sortBy: "liquidity",
          limit: 15
        }
      },
      {
        key: "trending-markets",
        toolId,
        toolName: "discover_trending_markets",
