  const topMarketData = topMarkets && topMarkets.status === "fulfilled" ? topMarkets.value : null;
  const trendingData = trendingMarkets && trendingMarkets.status === "fulfilled" ? trendingMarkets.value : null;

  const marketCandidates = [];
  if (Array.isArray(topMarketData?.markets)) marketCandidates.push(...topMarketData.markets);
  if (Array.isArray(trendingData?.trendingMarkets)) marketCandidates.push(...trendingData.trendingMarkets);

  const deduped = [];
  const seen = new Set();
  for (const m of marketCandidates) {
    const key = m && (m.conditionId || m.slug || m.url);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    deduped.push(m);
  }

  const ranked = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event on Polymarket",
    candidates: deduped,
    requiredTerms: ["politics"],
    avoidTerms: ["single outcome", "yes/no", "binary"],
    limit: 5
  });

  const shortlist = Array.isArray(ranked) ? ranked : [];
  const probeResults = [];
  let chosenEvent = null;
  let chosenOutcomes = null;

  for (const candidate of shortlist.slice(0, 3)) {
    if (!candidate || !candidate.slug) continue;

    const eventDetails = await callMcpSkill({
      toolId,
      toolName: "get_event_by_slug",
      args: { slug: candidate.slug }
    });

    const markets = Array.isArray(eventDetails?.markets) ? eventDetails.markets : [];
    if (markets.length > 1) {
      chosenEvent = {
        title: eventDetails?.event?.title || candidate.title || candidate.slug,
        slug: candidate.slug,
        url: candidate.url,
        conditionId: candidate.conditionId,
        liquidity: candidate.liquidity,
        volume24h: candidate.volume24h
      };

      const outcomes = await callMcpSkill({
        toolId,
        toolName: "get_event_outcomes",
        args: { slug: candidate.slug }
      });

      chosenOutcomes = outcomes;
      break;
    }

    probeResults.push({
      slug: candidate.slug,
      title: candidate.title,
      reason: "Not a multi-outcome event"
    });
  }

  if (!chosenEvent || !chosenOutcomes) {
    return {
      missingData: true,
      attemptedBranches: {
        parallelReadBatch: ["get_top_markets", "discover_trending_markets"],
        shortlistProbe: shortlist.slice(0, 3).map((c) => ({
          slug: c?.slug,
          title: c?.title,
          conditionId: c?.conditionId
        }))
      },
      stopReason: "Could not confirm a live multi-outcome politics event from the shortlisted candidates.",
      probeResults
    };
  }

  const outcomes = Array.isArray(chosenOutcomes?.outcomes) ? chosenOutcomes.outcomes : [];
  const sortedByPrice = [...outcomes].sort((a, b) => (b?.price ?? -Infinity) - (a?.price ?? -Infinity));
  const topFour = sortedByPrice.slice(0, 4);

  const selectedNames = topFour.map((o) => o?.name).filter(Boolean);

  const comparison = await callMcpSkill({
    toolId,
    toolName: "compare_event_outcome_quotes",
    args: {
      eventQuery: chosenEvent.title,
      outcomes: selectedNames,
      category: "politics",
      limit: 4
    }
  });

  const liquidityBatch = await callMcpSkillsParallel({
    label: "top-four-liquidity-check",
    calls: topFour
      .filter((o) => o && o.tokenId)
      .map((o) => ({
        key: o.name,
        toolId,
        toolName: "analyze_market_liquidity",
        args: {
          tokenId: o.tokenId
        }
      }))
  });

  const liquidityByOutcome = {};
  for (const entry of liquidityBatch.results) {
    if (entry.status === "fulfilled") {
      const value = entry.value;
      const marketName = value?.market || entry.key;
      liquidityByOutcome[marketName] = value;
