    avoidTerms: ["primary", "nominee", "election", "house", "senate", "district"],
  };

  const semanticTop = pickTopSemanticCandidates({
    target: geoLeg.target,
    candidates: combined,
    requiredTerms: geoLeg.requiredTerms,
