import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main() {
  // Probe -> decide -> execute
  // 1) Read-only discovery batch across different endpoints/tools.
  // 2) Locally rank the noisy Polymarket candidates with deterministic semantic targeting.
  // 3) Sequentially resolve the best candidate with shortlist-first follow-ups.
  // 4) Crossref the selected Polymarket market to likely Kalshi matches.
  // 5) Validate YES/NO semantics with rules text before judging any odds gap.

  const discoveryBatch = await callMcpSkillsParallel({
    label: "polymarket-trump-fed-discovery",
    calls: [
      {
        key: "trending",
        toolId,
        toolName: "discover_trending_markets",
        args: { limit: 20, sortBy: "volume", category: "politics" }
      },
      {
        key: "topMarkets",
        toolId,
        toolName: "get_top_markets",
        args: { limit: 20, sortBy: "volume", category: "politics" }
      }
    ]
  });

  const trending =
    discoveryBatch.results.find((r) => r.key === "trending")?.status === "fulfilled"
      ? discoveryBatch.results.find((r) => r.key === "trending").value
      : null;
  const topMarkets =
    discoveryBatch.results.find((r) => r.key === "topMarkets")?.status === "fulfilled"
      ? discoveryBatch.results.find((r) => r.key === "topMarkets").value
      : null;

  const trendingMarkets = Array.isArray(trending?.trendingMarkets) ? trending.trendingMarkets : [];
  const topMarketRows = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];

  const candidatePool = [...trendingMarkets, ...topMarketRows].filter(Boolean);

  const semanticTarget = "live high-volume Trump or Fed-related Polymarket market";
  const ranked = pickTopSemanticCandidates({
    target: semanticTarget,
    candidates: candidatePool,
    requiredTerms: ["trump", "fed"],
    avoidTerms: ["resolved", "expired"],
    limit: 5
  });

  const shortlist = Array.isArray(ranked) ? ranked : [];
  if (shortlist.length === 0) {
    return {
      missingData: ["No live Trump/Fed candidate survived semantic ranking"],
      attemptedBranches: ["discover_trending_markets politics volume", "get_top_markets politics volume"],
      stopReason: "No suitable Polymarket candidate found"
    };
  }

  // Shortlist-first sequential exploration on the same endpoint/tool family.
  const bestCandidate = shortlist[0];
  const candidateSlug = bestCandidate?.slug || null;
  const candidateConditionId = bestCandidate?.conditionId || null;

  const eventDetails = candidateSlug
    ? await callMcpSkill({
        toolId,
        toolName: "get_event_by_slug",
        args: { slug: candidateSlug }
      })
    : null;

  const primaryMarket = Array.isArray(eventDetails?.markets) ? eventDetails.markets[0] : null;
  const primaryTokenId = primaryMarket?.tokens?.find((t) => t?.outcome === "YES")?.token_id || null;

  if (!candidateSlug) {
    return {
      missingData: ["Could not resolve a candidate slug from discovery results"],
      attemptedBranches: ["semantic shortlist from discovery set"],
      stopReason: "Missing canonical market identifier"
    };
  }

  // Cross-venue matching after direct market resolution.
  const crossref = await callMcpSkill({
    toolId,
    toolName: "polymarket_crossref_kalshi",
    args: {
      title: bestCandidate?.title || bestCandidate?.market || "",
      keywords: [bestCandidate?.title, "Trump", "Fed", "Federal Reserve", "Powell"]
        .filter(Boolean)
        .join(" "),
      polymarketSlug: candidateSlug,
      limit: 5
    }
  });

  const kalshiResults = Array.isArray(crossref?.kalshiResults) ? crossref.kalshiResults : [];
  const bestKalshi = kalshiResults[0] || null;

  const semantics = bestKalshi
    ? {
        polymarketYesMeaning: "Polymarket YES means the market resolves true under the Polymarket event rules.",
        kalshiYesMeaning: bestKalshi.yesOutcomeMeans || null,
        kalshiNoMeaning: bestKalshi.noOutcomeMeans || null,
        rules: bestKalshi.rules || null,
        semanticAlignmentNeeded: true,
        alignmentVerdict: "requires_manual_rule_comparison"
      }
    : {
        semanticAlignmentNeeded: true,
        alignmentVerdict: "no_kalshi_match_found"
      };

  return {
    selectedPolymarketMarket: {
      title: bestCandidate?.title || null,
      slug: candidateSlug,
      url: bestCandidate?.url || null,
      conditionId: candidateConditionId,
      currentPrice: bestCandidate?.currentPrice || null,
      liquidity: bestCandidate?.liquidity || null,
      volume24h: bestCandidate?.volume24h || null,
      tokenId: primaryTokenId
    },
    kalshiMatches: kalshiResults.map((m) => ({
      title: m.title,
      ticker: m.ticker,
      yesPrice: m.yesPrice,
      matchScore: m.matchScore,
      url: m.url,
      yesOutcomeMeans: m.yesOutcomeMeans,

