    const liquidityCheck = await callMcpSkill({
      toolId,
      toolName: "analyze_market_liquidity",
      args: {
        slug: op.slug || undefined,
        conditionId: op.conditionId || undefined,
        marketQuery: op.market || undefined
      }
    });

    withLiquidityChecks.push({ op, liquidityCheck });
  }

  const scored = withLiquidityChecks.map(({ op, liquidityCheck }, index) => {
    const price = typeof op.currentPrice === "number" ? op.currentPrice : null;
    const liquidity = typeof op.liquidity === "number" ? op.liquidity : null;
    const volume24h = typeof op.volume24h === "number" ? op.volume24h : null;
    const spreadBps = typeof liquidityCheck?.spread?.bps === "number" ? liquidityCheck.spread.bps : null;
    const totalDepthUsd = typeof liquidityCheck?.depth?.totalDepthUsd === "number" ? liquidityCheck.depth.totalDepthUsd : null;
    const whaleCost = typeof liquidityCheck?.whaleCost?.sell1000Usd === "number" ? liquidityCheck.whaleCost.sell1000Usd : null;

    const liquidityScore = liquidity === null ? 0 : Math.min(liquidity / 50000, 1);
    const volumeScore = volume24h === null ? 0 : Math.min(volume24h / 100000, 1);
    const priceStabilityScore = price === null ? 0 : Math.max(0, 1 - Math.abs(price - 0.85) / 0.15);
    const spreadScore = spreadBps === null ? 0 : Math.max(0, 1 - Math.min(spreadBps / 200, 1));
    const depthScore = totalDepthUsd === null ? 0 : Math.min(totalDepthUsd / 50000, 1);
    const exitCostScore = whaleCost === null ? 0 : Math.max(0, 1 - Math.min(whaleCost / 5000, 1));

    const score =
      liquidityScore * 0.30 +
      volumeScore * 0.20 +
      priceStabilityScore * 0.15 +
      spreadScore * 0.15 +
      depthScore * 0.10 +
      exitCostScore * 0.10;

    return {
      rank: index + 1,
      market: op.market,
      url: op.url,
      conditionId: op.conditionId,
      slug: op.slug,
      currentPrice: op.currentPrice,
      liquidity: op.liquidity,
      volume24h: op.volume24h,
      impliedProbability: op.impliedProbability,
      opportunityType: op.opportunityType,
      suggestedSide: op.suggestedSide,
      confidence: op.confidence,
      score: Number(score.toFixed(4)),
      liquidityAnalysis: {
        spreadBps,
        totalDepthUsd,
        whaleCostAt5000: whaleCost,
        liquidityScore: liquidityCheck?.liquidityScore ?? null
      },
      whyThisOpportunity: op.whyThisOpportunity,
      riskFactors: Array.isArray(op.riskFactors) ? op.riskFactors : []
    };
  });

  scored.sort((a, b) => b.score - a.score);

  return {
    summary: result?.summary || null,
    rankingMethod: "Political markets only, then ranked by liquidity, 24h volume, and $5,000 exit quality (spread/depth/whale cost).",
    totalMatches: scored.length,
    markets: scored.slice(0, 10)
  };
}

